"""remediation_status.py

Polls the GitHub milestone for a no-go remediation and prints
a summary of open vs. closed issues by severity.

Run from CI on a schedule to push status to Slack.
"""
import subprocess
import json

def get_milestone_issues(repo, milestone):
    cmd = [
        "gh", "issue", "list",
        "--repo", repo,
        "--milestone", milestone,
        "--json", "number,title,state,labels,assignees",
        "--limit", "100",
    ]
    result = subprocess.run(cmd, capture_output=True, text=True, check=True)
    return json.loads(result.stdout)

def summarize(repo, milestone):
    issues = get_milestone_issues(repo, milestone)
    by_severity = {"CRITICAL": [], "MAJOR": [], "ADVISORY": []}
    for issue in issues:
        label_names = {l["name"] for l in issue["labels"]}
        if "severity:critical" in label_names:
            by_severity["CRITICAL"].append(issue)
        elif "severity:major" in label_names:
            by_severity["MAJOR"].append(issue)
        else:
            by_severity["ADVISORY"].append(issue)

    print(f"Remediation status for milestone: {milestone}")
    print(f"Repo: {repo}\n")
    all_blocking_resolved = True
    for severity in ("CRITICAL", "MAJOR", "ADVISORY"):
        bucket = by_severity[severity]
        if not bucket:
            continue
        open_count = sum(1 for i in bucket if i["state"] == "OPEN")
        closed_count = len(bucket) - open_count
        print(f"{severity}: {closed_count}/{len(bucket)} resolved")
        for issue in bucket:
            icon = "✓" if issue["state"] == "CLOSED" else "○"
            owners = ", ".join(a["login"] for a in issue["assignees"])
            print(f"  {icon} #{issue['number']} {issue['title'][:60]} [{owners}]")
        if severity in ("CRITICAL", "MAJOR") and open_count > 0:
            all_blocking_resolved = False

    print()
    if all_blocking_resolved:
        print("STATUS: Ready to schedule re-forum")
    else:
        print("STATUS: Remediation in progress — re-forum not yet schedulable")

if __name__ == "__main__":
    import argparse
    parser = argparse.ArgumentParser()
    parser.add_argument("--repo", required=True)
    parser.add_argument("--milestone", required=True)
    args = parser.parse_args()
    summarize(args.repo, args.milestone)
